def run(state):
    s = dict(state or {})
    s.setdefault("messages", [])
    s.setdefault("retry_count", 0)
    s.setdefault("current_phase", "pre_data_collection")
    s.setdefault("trigger_fallback", False)

    def _content(msg):
        if isinstance(msg, dict):
            return str(msg.get("content", ""))
        return str(getattr(msg, "content", msg))

    def _role(msg):
        if isinstance(msg, dict):
            return str(msg.get("role", "")).lower()
        return ""

    last_user = ""
    for m in reversed(s["messages"]):
        role = _role(m)
        if role in ("", "user", "human"):
            txt = _content(m).strip()
            if txt:
                last_user = txt
                break

    text = last_user.lower()
    frustration_terms = [
        "frustrated", "angry", "useless", "waste", "not working", "still not", "again", "fed up",
        "irritating", "annoying", "bad service", "terrible", "horrible", "wtf"
    ]
    frustrated = any(term in text for term in frustration_terms) and ("i'm done" not in text and "im done" not in text)

    if frustrated:
        if s.get("retry_count", 0) < 2:
            s["retry_count"] = s.get("retry_count", 0) + 1
            last_ai = ""
            for m in reversed(s["messages"]):
                role = _role(m)
                if role in ("assistant", "ai"):
                    last_ai = _content(m).strip()
                    break
