import re

def run(state):
    s = dict(state or {})
    s.setdefault("messages", [])
    s.setdefault("collected_data", {})
    s.setdefault("trigger_fallback", False)

    def _content(msg):
        if isinstance(msg, dict):
            return str(msg.get("content", ""))
        return str(getattr(msg, "content", msg))

    try:
        last_user = ""
        for m in reversed(s["messages"]):
            txt = _content(m).strip()
            if txt:
                last_user = txt
                break

        text = last_user
        lower = text.lower()
        collected = dict(s.get("collected_data") or {})

        for k, v in re.findall(r"([a-zA-Z_][a-zA-Z0-9_ ]{1,40})\s*[:=]\s*([^,;\n]+)", text):
            key = k.strip().lower().replace(" ", "_")
            collected[key] = v.strip()

        mobile_match = re.search(r"\b(\d{10})\b", lower)
        if mobile_match:
            collected.setdefault("mobile_number", mobile_match.group(1))

        veh_match = re.search(r"\b([A-Z]{2}\d{1,2}[A-Z]{1,3}\d{3,4})\b", text.replace("-", "").upper())
        if veh_match:
            collected.setdefault("vehicle_number", veh_match.group(1))

        date_match = re.search(r"\b(\d{4}-\d{2}-\d{2}|\d{2}/\d{2}/\d{4})\b", text)
        if date_match:
            collected.setdefault("policy_expiry_date", date_match.group(1))

        if "name is" in lower and "full_name" not in collected:
            maybe = text.split("name is", 1)[-1].strip(" .")
            if maybe:
                collected["full_name"] = maybe

        required_fields = ["full_name", "mobile_number", "vehicle_number", "policy_expiry_date"]
        missing = [f for f in required_fields if not collected.get(f)]

        s["collected_data"] = collected

        if missing:
            field = missing[0]
            s["is_form_complete"] = False
            s["current_phase"] = "data_collection"
            s["next_field_to_ask"] = {
                "field_name": field,
                "field_type": "string",
                "required": True,
                "prompt": f"Please provide {field.replace('_', ' ')}.",
            }
            s["send_now"] = False
            s["__route"] = "final_message_processing_node"
            return s

        summary_lines = []
        for k, v in collected.items():
            if k == "dp_details" and isinstance(v, dict):
                summary_lines.append("dp_details:")
                for nk, nv in v.items():
                    if nk != "dp_partner_id":
                        summary_lines.append(f"  - {nk}: {nv}")
            else:
                summary_lines.append(f"{k}: {v}")

        s["is_form_complete"] = True
        s["current_phase"] = "data_confirmation"
        s["next_field_to_ask"] = None
        s["final_message_context"] = "Please confirm these details:\n" + "\n".join(summary_lines)
        s["send_now"] = False
        s["__route"] = "final_message_processing_node"
        return s

    except Exception as exc:
        s["trigger_fallback"] = True
        s["final_message_context"] = f"Data collection failed: {exc}"
        s["__route"] = "fallback_node"
        return s

def run(state):
    s = dict(state or {})
    s.setdefault("messages", [])

    def _content(msg):
        if isinstance(msg, dict):
            return str(msg.get("content", ""))
        return str(getattr(msg, "content", msg))

    last_user = ""
    for m in reversed(s["messages"]):
        txt = _content(m).strip()
        if txt:
            last_user = txt
            break

    text = last_user.lower()
    confirmed_terms = ["yes", "confirm", "looks good", "correct", "all good", "okay proceed"]
    rejected_terms = ["no", "wrong", "change", "edit", "incorrect", "update"]

    confirmed = any(t in text for t in confirmed_terms)
    rejected = any(t in text for t in rejected_terms)

    if confirmed and not rejected:
        s["current_phase"] = "quote_processing"
        s["final_message_context"] = None
        s["__route"] = "quotes_processing_agent"
        return s

    if rejected:
        kept = {}
        for k in ["vertical", "dp_details"]:
            if k in (s.get("collected_data") or {}):
                kept[k] = s["collected_data"][k]
        s["collected_data"] = kept
        s["current_phase"] = "data_collection"
        s["is_form_complete"] = False
        s["final_message_context"] = "Understood. Please send the fields you want to change and their updated values."
        s["__route"] = "final_message_processing_node"
        return s

    s["current_phase"] = "data_confirmation"
    s["final_message_context"] = "I could not clearly understand that. Please confirm if the shared details are correct."
    s["__route"] = "final_message_processing_node"
    return s

def run(state):
    s = dict(state or {})
    s.setdefault("messages", [])

    next_field = s.get("next_field_to_ask")
    context = s.get("final_message_context")
    phase = s.get("current_phase")

    if next_field:
        prompt = next_field.get("prompt") or f"Please provide {next_field.get('field_name', 'the next required field')}."
        options = next_field.get("options") or []
        if options:
            rendered = []
            for opt in options:
                if isinstance(opt, dict):
                    label = opt.get("enum") or opt.get("value")
                    value = opt.get("value")
                    rendered.append(f"- {label} ({value})")
                else:
                    rendered.append(f"- {opt}")
            message = prompt + "\nOptions:\n" + "\n".join(rendered)
        else:
            message = prompt
    elif context:
        message = str(context)
    else:
        if phase == "addons" and s.get("quote_created"):
            message = "Please select your addons. If not needed, submit without addons."
        elif phase == "quote_processing":
            message = "Please wait while your quote is being processed."
        elif phase == "completed":
            message = "Quote journey completed successfully."
        else:
            message = "Please share the next detail to continue."

    s["messages"] = list(s.get("messages") or []) + [{"role": "assistant", "content": message}]
    s["last_response"] = message
    s["next_field_to_ask"] = None
    s["final_message_context"] = ""
    s["send_now"] = True
    return s
